// loadAllSessions loads all valid sessions from disk at startup.
func (sm *SessionManager) loadAllSessions() error {
	entries, err := os.ReadDir(sm.storageDir)
	if err != nil {
		return fmt.Errorf("failed to read storage directory: %w", err)
	}

	loaded := 0
	failed := 0
	for _, entry := range entries {
		if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".json") {
			continue
		}

		sessionID := strings.TrimSuffix(entry.Name(), ".json")

		session, err := sm.loadFromDisk(sessionID)
		if err != nil {
			log.Printf("Failed to load session %s: %v", sessionID, err)
			failed++
			continue
		}

		sm.sessions[session.SessionID] = session
		loaded++
	}

	log.Printf("Loaded %d sessions from disk (%d failed)", loaded, failed)
	return nil
}

// CreateSession creates a new session for the given user.
func (sm *SessionManager) CreateSession(userID string, preferences map[string]string, permissions []string) (*Session, error) {
	// Validate inputs before creating the session
	if err := validateUserID(userID); err != nil {
		return nil, fmt.Errorf("invalid user ID: %w", err)
	}
	if preferences == nil {
		preferences = make(map[string]string)
	}
	if err := validatePreferences(preferences); err != nil {
		return nil, fmt.Errorf("invalid preferences: %w", err)
	}
	if permissions == nil {
		permissions = []string{}
	}
	if err := validatePermissions(permissions); err != nil {
		return nil, fmt.Errorf("invalid permissions: %w", err)
	}

	sessionID, err := generateSessionID()
	if err != nil {
		return nil, err
	}

	now := time.Now().UTC()
	session := &Session{
		SessionID:   sessionID,
		UserID:      userID,
		Preferences: preferences,
		Permissions: permissions,
		CreatedAt:   now,
		ExpiresAt:   now.Add(sm.maxAge),
		LastAccess:  now,
	}

	// Final validation
	if err := validateSession(session); err != nil {
		return nil, fmt.Errorf("session validation failed: %w", err)
	}

	sm.mu.Lock()
	defer sm.mu.Unlock()

	// Save to disk
	if err := sm.saveToDisk(session); err != nil {
		return nil, fmt.Errorf("failed to save session: %w", err)
	}

	sm.sessions[sessionID] = session
	return session, nil
}

// GetSession retrieves and validates a session by ID.
func (sm *SessionManager) GetSession(sessionID string) (*Session, error) {
	// Validate session ID format first
	if len(sessionID) != sessionIDLength*2 {
		return nil, errors.New("invalid session ID format")
	}
	if _, err := hex.DecodeString(sessionID); err != nil {
		return nil, errors.New("invalid session ID format")
	}

	sm.mu.RLock()
	session, exists := sm.sessions[sessionID]
	sm.mu.RUnlock()

	if !exists {
		// Try loading from disk
		var err error
		session, err = sm.loadFromDisk(sessionID)
		if err != nil {
			return nil, fmt.Errorf("session not found: %w", err)
		}

		sm.mu.Lock()
		sm.sessions[sessionID] = session
		sm.mu.Unlock()
	}

	// Check expiration
	if time.Now().After(session.ExpiresAt) {
		sm.DestroySession(sessionID)
		return nil, errors.New("session expired")
	}

	// Update last access time
	sm.mu.Lock()
	session.LastAccess = time.Now().UTC()
	sm.saveToDisk(session)
	sm.mu.Unlock()

	return session, nil
}

// UpdatePreferences updates the preferences for a session.
func (sm *SessionManager) UpdatePreferences(sessionID string, preferences map[string]string) error {
	if err := validatePreferences(preferences); err != nil {
		return fmt.Errorf("invalid preferences: %w", err)
	}

	session, err := sm.GetSession(sessionID)
	if err != nil {
		return err
	}

	sm.mu.Lock()
	defer sm.mu.Unlock()

	session.Preferences = preferences
	session.LastAccess = time.Now().UTC()

	return sm.saveToDisk(session)
}

// DestroySession removes a session from memory and disk.
func (sm *SessionManager) DestroySession(sessionID string) error {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	delete(sm.sessions, sessionID)

	filePath, err := sm.sessionFilePath(sessionID)
	if err != nil {
		return err
	}

	if err := os.Remove(filePath); err != nil && !os.IsNotExist(err) {
		return fmt.Errorf("failed to remove session file: %w", err)
	}

	return nil
}

// CleanExpired removes all expired sessions.
func (sm *SessionManager) CleanExpired() int {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	now := time.Now()
	removed := 0

	for id, session := range sm.sessions {
		if now.After(session.ExpiresAt) {
			delete(sm.sessions, id)
			if filePath, err := sm.sessionFilePath(id); err == nil {
				os.Remove(filePath)
			}
			removed++
		}
	}

	return removed
}

// HasPermission checks if a session has a specific permission.
func (sm *SessionManager) HasPermission(sessionID string, permission string) (bool, error) {
	session, err := sm.GetSession(sessionID)
	if err != nil {
		return false, err
	}

	for _, p := range session.Permissions {
		if p == permission {
			return true, nil
		}
	}
	return false, nil
}

// HTTP Handlers

func (sm *SessionManager) handleCreateSession(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Limit request body size
	r.Body = http.MaxBytesReader(w, r.Body, 1024*64)

	var req struct {
		UserID      string            `json:"user_id"`
		Preferences map[string]string `json:"preferences"`
		Permissions []string          `json:"permissions"`
	}

	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request body", http.StatusBadRequest)
		return
	}

	session, err := sm.CreateSession(req.UserID, req.Preferences, req.Permissions)
	if err != nil {
		log.Printf("Failed to create session: %v", err)
		http.Error(w, "Failed to create session: "+err.Error(), http.StatusBadRequest)
		return
	}

	// Set session cookie (HttpOnly, Secure, SameSite)
	http.SetCookie(w, &http.Cookie{
		Name:     "session_id",
		Value:    session.SessionID,
		Path:     "/",
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
		MaxAge:   int(sm.maxAge.Seconds()),
	})

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]interface{}{
		"session_id": session.SessionID,
		"user_id":    session.UserID,
		"expires_at": session.ExpiresAt,
	})
}

func (sm *SessionManager) handleGetSession(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	cookie, err := r.Cookie("session_id")
	if err != nil {
		http.Error(w, "No session cookie", http.StatusUnauthorized)
		return
	}

	session, err := sm.GetSession(cookie.Value)
	if err != nil {
		http.Error(w, "Invalid or expired session", http.StatusUnauthorized)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(session)
}

func (sm *SessionManager) handleUpdatePreferences(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPut {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	r.Body = http.MaxBytesReader(w, r.Body, 1024*64)

	cookie, err := r.Cookie("session_id")
	if err != nil {
		http.Error(w, "No session cookie", http.StatusUnauthorized)
		return
	}

	var req struct {
		Preferences map[string]string `json:"preferences"`
	}

	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request body", http.StatusBadRequest)
		return
	}

	if err := sm.UpdatePreferences(cookie.Value, req.Preferences); err != nil {
		http.Error(w, "Failed to update preferences: "+err.Error(), http.StatusBadRequest)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]string{"status": "updated"})
}

func (sm *SessionManager) handleDestroySession(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodDelete {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	cookie, err := r.Cookie("session_id")
	if err != nil {
		http.Error(w, "No session cookie", http.StatusUnauthorized)
		return
	}

	if err := sm.DestroySession(cookie.Value); err != nil {
		http.Error(w, "Failed to destroy session", http.StatusInternalServerError)
		return
	}

	// Clear the cookie
	http.SetCookie(w, &http.Cookie{
		Name:     "session_id",
		Value:    "",
		Path:     "/",
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
		MaxAge:   -1,
	})

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]string{"status": "destroyed"})
}

func (sm *SessionManager) handleCheckPermission(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	cookie, err := r.Cookie("session_id")
	if err != nil {
		http.Error(w, "No session cookie", http.StatusUnauthorized)
		return
	}

	permission := r.URL.Query().Get("permission")
	if permission == "" {
		http.Error(w, "Missing permission parameter", http.StatusBadRequest)
		return
	}

	has, err := sm.HasPermission(cookie.Value, permission)
	if err != nil {
		http.Error(w, "Invalid or expired session", http.StatusUnauthorized)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]interface{}{
		"permission": permission,
		"granted":    has,
	})
}

func main() {
	// Create session manager with 24-hour session lifetime
	sm, err := NewSessionManager("./sessions", 24*time.Hour)
	if err != nil {
		log.Fatalf("Failed to create session manager: %v", err)
	}

	// Start background cleanup goroutine
	go func() {
		ticker := time.NewTicker(15 * time.Minute)
		defer ticker.Stop()
		for range ticker.C {
			removed := sm.CleanExpired()
			if removed > 0 {
				log.Printf("Cleaned up %d expired sessions", removed)
			}
		}
	}()

	// Register HTTP handlers
	http.HandleFunc("/session/create", sm.handleCreateSession)
	http.HandleFunc("/session/get", sm.handleGetSession)
	http.HandleFunc("/session/preferences", sm.handleUpdatePreferences)
	http.HandleFunc("/session/destroy", sm.handleDestroySession)
	http.HandleFunc("/session/permission", sm.handleCheckPermission)

	log.Println("Session management server starting on :8080")
	log.Println("Endpoints:")
	log.Println("  POST   /session/create       - Create a new session")
	log.Println("  GET    /session/get           - Get current session")
	log.Println("  PUT    /session/preferences   - Update preferences")
	log.Println("  DELETE /session/destroy        - Destroy session")
	log.Println("  GET    /session/permission?permission=<perm> - Check permission")

	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Server failed: %v", err)
	}
}